change.add:
{hasFilter && (
  <div className="flex items-center gap-2">
    <Checkbox
      id="historic"
      checked={currentHistoric}
      onCheckedChange={(checked) => {
        if (checked) {
          updateFilter("historic", "true")
        } else {
          const newParams = new URLSearchParams(searchParams.toString())
          newParams.delete("historic")
          router.push(`${basePath}?${newParams.toString()}`)
        }
      }}
    />
    <Label htmlFor="historic" className="text-sm cursor-pointer">
      Historic Summary
    </Label>
  </div>
)}
